                                    let ts2 = std::time::SystemTime::now()
                                        .duration_since(std::time::UNIX_EPOCH)
                                        .unwrap_or_default()
                                        .as_secs();
                                    ui.chat_lines.push(ChatLine::User(prompt.clone(), ts2));
